								{{endif}}
								{{if isset($url['title']) AND $url['title']}} data-ipsDialog-title='{lang="$url['title']"}'{{endif}}
								{{if isset($url['flashMessage'])}} data-ipsdialog-flashmessage="{lang="$url['flashMessage']"}"{{endif}}
								>{lang="$k"}</a>
							</li>
						{{endforeach}}
					</ul>
				</div>
