}

/* Hide widget control on phones */
@media screen and (max-width: 767px) {
	#elWidgetControls {
		display: none !important;
	}
}

html[dir="ltr"] #elWidgetControls {
	left: 0;
	border-radius: 0 3px 3px 0;
