}

.cAnnouncementsFloat
{
	position: fixed;
	margin: 0px;
	width: 100%;
	top: 0px;
}

	a[data-role="dismissAnnouncement"] {
		display: inline-block;
		background: rgba(0,0,0,0.6);
		width: 30px;
		height: 30px;
		border-radius: 30px;
		line-height: 28px;
		text-align: center;
		color: #fff;
		border-bottom: 0;
		font-size: 18px;
		position: absolute;
		right: 15px;
		top: 9px;
	}

#cAnnouncementSidebar {
	margin-top: 30px;
	position: relative;
	min-width: 295px;
	max-width: 100%;
}

	#cAnnouncementSidebar h3 {
		color: {theme="widget_title_font"};
		text-align: center;
		font-size: 12px;
		text-transform: uppercase;
		margin-top: -20px;
	}

	#cAnnouncementSidebar a:before {
		content: '\f05a';
		float: right;
		font-family: FontAwesome;
		font-size: 20px;
		margin-left: 5px;
	}
	#cAnnouncementSidebar ul {
		list-style: none;
		margin: 0;
		padding: 0;
	}
	#cAnnouncementSidebar ul > li {
		display: block !important;
		margin: 3px 10px;
		border-bottom: 1px solid rgba(0,0,0,0.075);
	}
	#cAnnouncementSidebar ul > li > a {
