	justify-content: center;
	align-items: center;
	background: {theme="item_status"};
	color: #fff;
	border-radius: 50%;
	padding: 10px;
	height: 70px;
	width: 70px;
	top: -30px;
	position: relative;
	margin-left: auto;
	margin-right: auto;
	left: 0;
	right: 0;
