}

/* EMOJI */
ul.cEmojiMenu.ipsMenu {
	display: flex;
	flex-wrap: wrap;
	padding: 7px;
	max-height: 191px; /* rather precise value allows half a row to be seen, to indicate it's scrollable */
	overflow: auto;
	max-width: 100% !important;
	margin: 10px 15px 0 15px;
}

	ul.cEmojiMenu.ipsMenu > li {
		min-width: 150px;
		width: 25%;
		margin-bottom: 4px;
	}

		ul.cEmojiMenu.ipsMenu > li > a,
		ul.cEmojiMenu.ipsMenu > li > a:first-child,
		ul.cEmojiMenu.ipsMenu > li > a:last-child {
			padding: 3px 10px;
			border-radius: 20px;
			display: flex;
			align-items: center;
		}

			ul.cEmojiMenu.ipsMenu > li > a > span[data-role="shortCode"] {
				overflow: hidden;
				text-overflow: ellipsis;
				white-space: nowrap;
				display: block;
				min-width: 0;
			}

		ul.cEmojiMenu.ipsMenu > li .ipsEmoji {
			font-size: 16px;
		}

body {
	background-color: #070707;
	color: #EEF1F5;
	font-family: 'Muli', sans-serif;
}

*:not(.fa) {
    font-family: 'Muli', sans-serif !important;
}

a {
	color: #EEF1F5;
	transition: color .3s ease-in-out;
}

a:hover {
	color: #2F54CF;
}

.ipsLayout_container {
    max-width: 1630px;
}

.ps-header {
    background-color: transparent;
    height: 105px;
    z-index: 1;
    z-index: 999;
}

.ps-menu {
    padding: 0;
    margin: 0;
}

.ps-menu > a {
    display: flex;
    flex-direction: column;
    float: left;
    height: 95px;
    padding: 20px 10px;
    min-width: 120px;
    text-align: center;
}

.ps-menu > a.active {
  	position: relative;
}

.ps-menu > a.active:after {
	content: '';
  	display: block;
  	position: absolute;
  	top: 0;
  	left: 0;
    width: 100%;
    height: 100%;
	background-image: url({resource="puffysticks/menu-active.svg" app="core" location="front"});
  	background-size: cover;
}

.menu-item_icon {
    display: block;
    align-self: center;
    width: 30px;
    height: 30px;
    background-position: center;
    background-repeat: no-repeat;
    position: relative;
    top: 12px;
    transition: all .3s ease-in-out;
}

.ps-menu > a:hover > .menu-item_icon,
.ps-menu > a.active > .menu-item_icon,
.ps-menu > a.hover > .menu-item_icon {
	top: 0;
}

.ps-menu > a[data-psmenukey="menu_Home"] > .menu-item_icon {
    background-size: auto 20px;
	background-image: url({resource="puffysticks/home.svg" app="core" location="front"});
}

.ps-menu > a[data-psmenukey="menu_Home"]:hover > .menu-item_icon,
