.ps-slider {
    overflow: hidden;
    padding: 0;
    max-width: 1600px;
    position: relative;
    height: 722px;
}

.ps-slider > div:first-of-type {
    height: 100%;
    display: flex;
    position: relative;
    left: 0;
    transition: all .5s ease-in-out;
    z-index: 3;
}

.ps-slider-child {
    width: 100%;
    position: relative;
    background-size: cover;
    background-position: center;
    z-index: 1;
}

.ps-slider-child:before {
    content: '';
    display: block;
    height: 100%;
    width: 100%;
    position: absolute;
    z-index: -1;
    left: 0;
    top: 0;
    background-image: url({resource="puffysticks/sliderov.png" app="core" location="front"});
}

.ps-slider-child:after {
    content: '';
    background-image: url({resource="puffysticks/slider-overlay.svg" app="core" location="front"});
    position: absolute;
    width: 100%;
    height: 100%;
    top: 0;
    right: 0;
    background-size: cover;
    background-position: center;
    z-index: -2;
}

