    color: inherit;
    font-size: 14px;
    font-weight: bold;
}

.ipsPagination li:not( .ipsPagination_pageJump ):not( .ipsPagination_mini ) .fa {
    color: transparent;
    position: relative;
}

.ipsPagination li:not( .ipsPagination_pageJump ):not( .ipsPagination_mini ) .fa:after {
    content: '';
    display: block;
    width: 0;
    height: 0;
    border-width: 9px;
    border-style: solid;
    border-color: transparent #5F76F2 #5F76F2 transparent;
    transform: scale( .5 ) rotateZ( -45deg );
    border-radius: 5px;
    position: absolute;
    top: 5px;
    left: 10px;
}

.ipsPagination li:not( .ipsPagination_pageJump ):not( .ipsPagination_mini ) .fa-angle-double-left:after { 
    transform: scale( .5 ) rotateZ( 135deg );
}

.ipsPagination_page.ipsPagination_active {
    position: relative;
    z-index: 1;
}

.ipsPagination_page.ipsPagination_active > a {
    color: #eef1f5 !important;
}

.ipsPagination_page.ipsPagination_active:after {
    content: '';
    display: block;
    height: 40px;
    width: 100%;
    background-color: #5D67C1;
    border-radius: 4px;
    z-index: -1;
    position: absolute;
    top: -8px;
}

.ipsPagination li:not( .ipsPagination_pageJump ):not( .ipsPagination_mini ) .fa:before {
    content: '';
    height: 28px;
    width: 30.63px;
    background-image: url({resource="puffysticks/pagination.svg" app="core" location="front"});
    background-size: cover;
    position: relative;
    top: 0;
    left: 0;
    transform: rotateY( 180deg );
    display: block;
}

.ipsPagination_first > a {
    position: absolute !important;
    top: -3px !important;
    left: -24px;
    padding: 0 !important;
    height: 31px !important;
    width: 28px !important;
}

.ipsPagination_first:after {
    content: '';
    display: block;
    width: 10px;
    height: 23.5px;
    background-color: #0c0c0e;
    position: absolute;
    top: 0.04em;
    left: -2px;
}

.ipsPagination > li.ipsPagination_inactive {
    display: inline-block;
}

.ipsPagination_last > a {
    position: absolute !important;
    top: -3px !important;
    right: -22px;
    padding: 0 !important;
    height: 31px !important;
    width: 28px !important;
}

.ipsPagination li:not( .ipsPagination_pageJump ):not( .ipsPagination_mini ).ipsPagination_last .fa:before {
    transform: rotateY( 0deg );
}

.ipsPagination li:not( .ipsPagination_pageJump ):not( .ipsPagination_mini ).ipsPagination_last .fa:after {
    left: 4px;
}

.ipsPagination_last:after {
    content: '';
    display: block;
    width: 10px;
    height: 23.5px;
    background-color: #0c0c0e;
    position: absolute;
    top: 0.04em;
    right: -2px;
}

